const items = $input.all();
const item = items[0].json;

const CATEGORY_TO_QUEUE = {
  'Bug Report': 'Engineering',
  'Feature Request': 'Product',
  'Billing Issue': 'Billing',
  'Technical Question': 'IT/Security',
  'Incident/Outage': 'Engineering-Urgent'
};

const ESCALATION_KEYWORDS = [
  'outage', 'down for all users', 'all users affected',
  'system down', 'critical failure', 'data breach',
  'security incident', 'multiple users affected'
];

const CONFIDENCE_THRESHOLD = 0.70;

// --- Validate and clamp confidence based on signal fields ---
const single = item.single_category_match;
const alt = item.alternative_category;
const uncertain = item.user_expresses_uncertainty;
const identifiers = item.explicit_identifiers_present;
let confidence = item.confidence;
let confidence_clamped = false;

let lo, hi;
if (!single && alt !== null) {
  lo = 0.50; hi = 0.75;
} else if (!single || uncertain) {
  lo = 0.60; hi = 0.82;
} else if (single && !uncertain && identifiers) {
  lo = 0.90; hi = 0.97;
} else if (single && !uncertain && !identifiers) {
  lo = 0.82; hi = 0.92;
} else {
  lo = 0.70; hi = 0.90;
}

if (confidence < lo || confidence > hi) {
  confidence = Math.max(lo, Math.min(hi, parseFloat(confidence.toFixed(2))));
  confidence_clamped = true;
}

let escalation_needed = item.escalation_needed;
let escalation_reason = item.escalation_reason;

// Priority override: Incidents are always High
let priority = item.priority;
if (item.category === 'Incident/Outage') {
  priority = 'High';
}

// Route to queue (pure mapping, no side effects)
let destination_queue = CATEGORY_TO_QUEUE[item.category] || 'Fallback-Escalation';

const message_lower = item.message.toLowerCase();

if (!escalation_needed) {
  if (confidence < CONFIDENCE_THRESHOLD) {
    escalation_needed = true;
    escalation_reason = 'Low confidence (' + confidence.toFixed(2) + ') below threshold (' + CONFIDENCE_THRESHOLD + ')';
  }

  for (const kw of ESCALATION_KEYWORDS) {
    if (message_lower.includes(kw)) {
      escalation_needed = true;
      escalation_reason = "Escalation keyword detected: '" + kw + "'";
      break;
    }
  }

  if (item.category === 'Billing Issue') {
    const amountMatch = item.message.match(/\$\s*([\d,]+(?:\.\d{2})?)/);
    if (amountMatch) {
      const amount = parseFloat(amountMatch[1].replace(/,/g, ''));
      if (amount > 500) {
        escalation_needed = true;
        escalation_reason = 'Billing amount $' + amount.toFixed(2) + ' exceeds $500 threshold';
      }
    }
  }
}

if (escalation_needed) {
  destination_queue = 'Escalation';
}

return [{
  json: {
    ...item,
    confidence: confidence,
    confidence_clamped: confidence_clamped,
    priority: priority,
    destination_queue: destination_queue,
    escalation_needed: escalation_needed,
    escalation_reason: escalation_reason,
    human_review_flag: escalation_needed
  }
}];

const items = $input.all();
items[0].json.routing_destination = "Escalation Queue";
return items;

const items = $input.all();
const item = items[0].json;

const outputUrl = $env.OUTPUT_WEBHOOK_URL;

if (outputUrl) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: outputUrl,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(item)
    });
  } catch (e) {
    // Log failure but don't block the pipeline
  }
}

return items;
